export type ErrorCorrectionLevel = "L" | "M" | "Q" | "H";
export type QrRenderOptions = {
    darkColor?: string;
    errorCorrectionLevel?: ErrorCorrectionLevel;
    lightColor?: string;
    margin?: number;
    scale?: number;
    width?: number;
};
export type TerminalRenderOptions = QrRenderOptions & {
    small?: boolean;
};
export type OutputType = "png-base64" | "png-data-url" | "svg" | "terminal" | "utf8";
